const grpc = require('grpc');
const protoLoader = require('@grpc/proto-loader');

// Load the protocol definition
const packageDefinition = protoLoader.loadSync(
  'path/to/your/service.proto',
  {
    keepCase: true,
    longs: String,
    enums: String,
    defaults: true,
    oneofs: true
  }
);
const serviceProto = grpc.loadPackageDefinition(packageDefinition).YourServicePackage.YourService;

// gRPC server address
const grpcServerAddress = 'your-grpc-server-address';

function createGrpcClient() {
  return new serviceProto(grpcServerAddress, grpc.credentials.createInsecure());
}

function forwardHeadersToGrpc(req, res) {
  const metadata = new grpc.Metadata();

  // Forward common headers
  if (req.headers['user-agent']) {
    metadata.add('user-agent', req.headers['user-agent']);
  }
  if (req.headers['x-forwarded-for']) {
    metadata.add('x-forwarded-for', req.headers['x-forwarded-for']);
  }

  // Forward custom headers
  Object.keys(req.headers).forEach(header => {
    if (header.startsWith('x-custom-')) { // Adjust the prefix as needed
      metadata.add(header, req.headers[header]);
    }
  });

  return metadata;
}

